import { Component, OnInit, inject } from '@angular/core';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { PeliculaService } from '../../core/services/pelicula.service';
import { Pelicula } from '../../core/interfaces/pelicula.interface';

@Component({
  selector: 'app-detalle',
  standalone: true,
  imports: [RouterLink],
  templateUrl: './detalle.component.html'
})
export class DetalleComponent implements OnInit {
  private route = inject(ActivatedRoute);
  private peliculaService = inject(PeliculaService);
  private router = inject(Router);

  pelicula: Pelicula | null = null;
  cargando = true;
  error = false;

  ngOnInit(): void {
    // Uso de paramMap para leer el :id de la URL
    this.route.paramMap.subscribe(params => {
      const id = Number(params.get('id'));
      if (!id) { this.router.navigate(['/404']); return; }

      this.peliculaService.getPeliculaById(id).subscribe({
        next: (res) => { this.pelicula = res.data; this.cargando = false; },
        error: () => { this.error = true; this.cargando = false; }
      });
    });
  }

  irAResenas(): void {
    if (this.pelicula) {
      // Navegación programática con parámetro
      this.router.navigate(['/resenas', this.pelicula.id]);
    }
  }
}

@if (cargando) {
  <div class="text-center py-5">
    <div class="spinner-border text-warning"></div>
    <p>Cargando información...</p>
  </div>
}

@if (error) {
  <div class="alert alert-danger">
    No se pudo cargar la película. <a routerLink="/catalogo">Volver al catálogo</a>
  </div>
}

@if (!cargando && pelicula) {
  <div class="row g-4">
    <div class="col-md-4">
      <!-- property binding [src] [alt] -->
      <img [src]="pelicula.poster_url" [alt]="pelicula.titulo"
           class="img-fluid rounded shadow w-100" style="max-height:500px;object-fit:cover">
    </div>
    <div class="col-md-8">
      <!-- interpolación -->
      <h1>{{ pelicula.titulo }}</h1>
      <p class="text-muted">{{ pelicula.director }} · {{ pelicula.anio }}</p>

      @if (pelicula.genero) {
        <span class="badge bg-secondary me-2">{{ pelicula.genero }}</span>
      }
      <span class="badge" [class.bg-primary]="pelicula.tipo==='pelicula'" [class.bg-success]="pelicula.tipo==='serie'">
        {{ pelicula.tipo === 'pelicula' ? 'Película' : 'Serie' }}
      </span>

      <hr>
      <h5>Sinopsis</h5>
      <p>{{ pelicula.sinopsis }}</p>

      <div class="d-flex gap-2 flex-wrap mt-4">
        <!-- Event binding + navegación programática -->
        <button class="btn btn-warning" (click)="irAResenas()">💬 Ver reseñas</button>
        <a routerLink="/catalogo" class="btn btn-outline-secondary">← Volver</a>
      </div>
    </div>
  </div>
}
